import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import Loginpage from "./Components/Loginpage"; // Login page component
import Registration from "./Components/Registration"; // Registration page component
import AdminDashboard from "./Pages/Admin/AdminDashboard"; // Admin dashboard page
import RegUser from "./Pages/Admin/RegUser"; //RegUser Page
import AccidentReport from "./Pages/Admin/AccidentReport";
import LiveAlerts from "./Pages/Admin/LiveAlerts";
import Emergency  from "./Pages/Admin/Emergency";
import Counselor from "./Pages/Admin/Counselor";
import Mlprediction from "./Pages/Admin/Mlprediction";
import Feedback from "./Pages/Admin/Feedback";
import Settings from "./Pages/Admin/Settings";
import Usericon from "./Pages/User/Usericon";
import UserDash from "./Pages/User/UserDash";
import UserProfile from "./Pages/User/UserProfile";


function App() {
  return (
    <Router>
      <Routes>
        {/* Default route */}
        <Route path="/" element={<Loginpage />} />

        {/* Login route */}
        <Route path="/Loginpage" element={<Loginpage />} />

        {/* Registration route */}
        <Route path="/Registration" element={<Registration />} />

        {/* Admin dashboard route */}
       <Route path="/AdminDashboard" element={<AdminDashboard />} />

        {/* RegUser route */}
       <Route path="/RegUser" element={<RegUser />} />

        {/* AccidentReport route */}
       <Route path="/AccidentReport" element={<AccidentReport />} />

       {/* LiveAlerts route */}
       <Route path="/LiveAlerts" element={<LiveAlerts />} />
       <Route path="/Emergency" element={<Emergency />} />
       <Route path="/Mlprediction" element={<Mlprediction />} />
       {/* Counselor route */}
       <Route path="/Counselor" element={<Counselor />} />
       {/* feedback route */}
       <Route path="/Feedback" element={<Feedback />} />
       {/* Settings route */}
       <Route path="/Settings" element={<Settings />} />
       {/* usericon route */}
       <Route path="/Usericon" element={<Usericon />} />

       <Route path="/UserDash" element={<UserDash />} />
        <Route path="/UserProfile" element={<UserProfile />} />




      </Routes>
    </Router>
  );
}

export default App;
